let arr = ['apple', 'banana', 'cherry', 'date', 'elderberry'];
let index = arr.indexOf('cherry');
if (index !== -1) {
    arr.splice(index, 1);
}
console.log(arr); // Expected output: ['apple', 'banana', 'date', 'elderberry']

let arr = [1, 2, 3, 4, 5];
arr.reverse();
console.log(arr); // Expected output: [5, 4, 3, 2, 1]

let arr = ['This', 'is', 'an', 'array'];
let str = arr.join(' ');
console.log(str); // Expected output: 'This is an array'

let arr = [5, 3, 2, 4, 1];
arr.sort((a, b) => a - b);
console.log(arr); // Expected output: [1, 2, 3, 4, 5]

let arr = [1, 2, 3, 4, 5];
let doubledArr = arr.map(x => x * 2);
console.log(doubledArr); // Expected output: [2, 4, 6, 8, 10]

let arr = [5, 12, 8, 130, 44];
let found = arr.find(element => element > 10);
console.log(found); // Expected output: 12

let arr = [1, 30, 39, 29, 10, 13];
let isEveryElementLessThan30 = arr.every(val => val <= 30);
console.log(isEveryElementLessThan30); // Expected output: false

let arr = ['a', 'b', 'c', 'd', 'e'];
let newArr = arr.slice(1, 4);
console.log(newArr); // Expected output: ['b', 'c', 'd']

let arr = ['a', 'b', 'c', 'd', 'e'];
let index = arr.indexOf('d');
console.log(index); // Expected output: 3

let arr = ['Hello', 'World', '!'];
let str = arr.join(' ');
console.log(str); // Expected output: 'Hello World !'

let arr = [5, 2, 8, 1, 7];
arr.sort((a, b) => a - b);
console.log(arr); // Expected output: [1, 2, 5, 7, 8]

let arr = [1, 2, 3, 4, 5];
let sum = arr.reduce((accumulator, current) => accumulator + current, 0);
console.log(sum); // Expected output: 15

let arr = [1, 2, 3, 4, 5];
let evenNumbers = arr.filter(num => num % 2 == 0);
console.log(evenNumbers); // Expected output: [2, 4]

let arr = ['apple', 'banana', 'cherry'];
let isBananaIncluded = arr.includes('banana');
console.log(isBananaIncluded); // Expected output: true

let arr = ['apple', 'banana', 'cherry'];
arr.reverse();
console.log(arr); // Expected output: ['cherry', 'banana', 'apple']

let arr = ['banana', 'cherry', 'apple'];
arr.sort();
console.log(arr); // Expected output: ['apple', 'banana', 'cherry']

let arr = ['apple', 'banana'];
arr.push('cherry');
console.log(arr); // Expected output: ['apple', 'banana', 'cherry']

let arr = ['apple', 'banana', 'cherry'];
arr.pop();
console.log(arr); // Expected output: ['apple', 'banana']

let arr = ['apple', 'banana', 'cherry', 'banana'];
let index = arr.indexOf('banana');
console.log(index); // Expected output: 1

let arr = ['banana', 'apple', 'cherry'];
arr.sort();
console.log(arr); // Expected output: ['apple', 'banana', 'cherry']
